const $=s=>document.querySelector(s); const $$=s=>[...document.querySelectorAll(s)];
function escapeHTML(value){return String(value).replace(/[&<>'"]/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]))}
function payloadOf(item){let payload=item?.payload_json||item||{};try{if(typeof payload==='string')payload=JSON.parse(payload)}catch(error){return{}}return payload||{}}
function monthOf(item){return String(item?.survey_month||payloadOf(item).surveyMonth||item?.submitted_at||'').slice(0,7)}
function previousMonth(month){const [year,value]=month.split('-').map(Number);const date=new Date(Date.UTC(year,value-2,1));return date.toISOString().slice(0,7)}
function monthLabel(month){if(!/^\d{4}-\d{2}$/.test(month))return month;const [year,value]=month.split('-');return `${year}년 ${Number(value)}월`}
function latestByStudent(responses,month){const latest=new Map();responses.filter(item=>monthOf(item)===month&&!item.analysis_excluded).sort((a,b)=>new Date(b.submitted_at||payloadOf(b).submittedAt||0)-new Date(a.submitted_at||payloadOf(a).submittedAt||0)).forEach(item=>{const number=Number(item.student_number||payloadOf(item).studentNumber);if(number&&!latest.has(number))latest.set(number,item)});return latest}
function quoted(value,max=180){const text=String(value||'').trim();return text?`“${text.length>max?`${text.slice(0,max)}…`:text}”`:''}
function signalTag(type){return type==='urgent'?'즉시 확인':'지속 관찰'}
function standardDeviation(values){if(!values.length)return 0;const average=values.reduce((sum,value)=>sum+value,0)/values.length;return Math.sqrt(values.reduce((sum,value)=>sum+(value-average)**2,0)/values.length)}
function updateMonthSelector(){const months=[...new Set(allResponses.map(monthOf).filter(month=>/^\d{4}-\d{2}$/.test(month)))].sort().reverse();if(!months.length)months.push(new Date().toISOString().slice(0,7));if(!months.includes(selectedAnalysisMonth))selectedAnalysisMonth=months[0];const options=months.map(month=>`<option value="${month}" ${month===selectedAnalysisMonth?'selected':''}>${monthLabel(month)}</option>`).join('');['#analysisMonth','#surveyMonth'].forEach(id=>{const selector=$(id);if(selector)selector.innerHTML=options})}
function analyzeResponses(responses,month){
  const current=latestByStudent(responses,month);const previous=latestByStudent(responses,previousMonth(month));const found=[];let id=1;
  const add=(type,item,title,summary,evidence,hypotheses,observation)=>found.push({id:id++,type,tag:signalTag(type),name:item?.student_name||payloadOf(item).studentName||'학생',studentNumber:Number(item?.student_number||payloadOf(item).studentNumber)||null,studentId:item?.student_id||null,sourceResponseId:item?.id||null,submittedAt:item?.submitted_at||payloadOf(item).submittedAt||null,title,summary,evidence:evidence.filter(Boolean),hypotheses,observation});
  current.forEach((item,number)=>{const payload=payloadOf(item);const help=String(payload.helpNow||'');const worry=payload.studentState?.worryDetail;const hurt=payload.peerObservations?.hurt||{};
    if(/바로|즉시/.test(help))add('urgent',item,'지금 도움이 필요하다고 응답했어요','학생이 바로 도움을 요청했습니다.',[quoted(worry||hurt.detail),'도움 요청: 바로 도와주세요',hurt.sourceType?`사건 맥락: ${hurt.sourceType}${hurt.frequency?` · ${hurt.frequency}`:''}${hurt.ongoing?' · 지금도 계속됨':''}`:''],['현재 어려움이 계속되는 상황','도움을 요청할 만큼 불편한 상황','학생이 안전한 대화를 원하는 상황'],'오늘 중 안전한 장소에서 현재 상황과 학생이 원하는 도움을 먼저 확인합니다.');
    else if(/이번 주/.test(help))add('week',item,'이번 주에 이야기하고 싶다고 응답했어요','학생이 교사와의 대화를 요청했습니다.',[quoted(worry||hurt.detail),'도움 요청: 이번 주에 이야기하고 싶어요'],['최근 학교생활 고민','친구 관계에서의 불편함','교사와 확인하고 싶은 개인적인 상황'],'이번 주 안에 개별적으로 편안한 시간과 장소를 정해 이야기를 듣습니다.');
    const before=previous.get(number);if(before){const nowRatings=payload.selfRatings||{};const oldRatings=payloadOf(before).selfRatings||{};const labels={study:'학습',listening:'경청',respect:'관계 존중',manners:'예의',responsibility:'책임감'};const drops=Object.keys(labels).filter(key=>Number(oldRatings[key]?.score)-Number(nowRatings[key]?.score)>=2);if(drops.length)add('week',item,'자기평가가 지난달보다 크게 낮아졌어요',drops.map(key=>`${labels[key]} ${oldRatings[key].score}→${nowRatings[key].score}`).join(' · '),drops.map(key=>`${labels[key]}: ${previousMonth(month)} ${oldRatings[key].score}점 → ${month} ${nowRatings[key].score}점`).concat(quoted(worry)),['최근 경험이나 자신감의 변화','응답 시점의 일시적인 감정','학습·관계 환경의 변화'],'낮아진 항목과 관련된 최근 상황을 학생에게 묻고 수업·쉬는 시간 행동을 함께 살펴봅니다.')}});
  const names=classSettings.students.map(student=>student.name).filter(Boolean);const helpMentions=new Map();current.forEach(item=>{const detail=String(payloadOf(item).peerObservations?.needsHelp?.detail||'');names.forEach(name=>{if(detail.includes(name)){if(!helpMentions.has(name))helpMentions.set(name,[]);helpMentions.get(name).push({item,detail})}})});helpMentions.forEach((mentions,name)=>{const reporters=new Set(mentions.map(({item})=>Number(item.student_number||payloadOf(item).studentNumber)));if(reporters.size>=2){const target=classSettings.students.find(student=>student.name===name);add('week',{student_name:name},'여러 친구가 도움이 필요하다고 언급했어요',`서로 다른 ${reporters.size}명의 응답에 등장했습니다.`,mentions.slice(0,3).map(({item,detail})=>`${item.student_name||payloadOf(item).studentName}: ${quoted(detail)}`),['학습이나 활동에서 도움이 필요한 상황','친구 관계에서 지원이 필요한 상황','친구들이 걱정하거나 함께 돕고 싶은 상황'],'학습·놀이·모둠 상황을 살펴본 뒤 학생에게 필요한 도움이 있는지 부담 없이 확인합니다.')}});
  const relationMap=new Map();current.forEach((item,rater)=>{(payloadOf(item).relationships||[]).forEach(row=>relationMap.set(`${rater}:${Number(row.targetNumber)}`,Number(row.score)))});const incoming=new Map();relationMap.forEach((score,key)=>{const target=Number(key.split(':')[1]);if(!incoming.has(target))incoming.set(target,[]);incoming.get(target).push(score)});incoming.forEach((values,target)=>{if(values.length<4)return;const low=values.filter(value=>value<=2).length/values.length;const high=values.filter(value=>value>=4).length/values.length;const sd=standardDeviation(values);if(low>=.25&&high>=.25&&sd>=1.3){const student=classSettings.students.find(row=>Number(row.number)===target);add('week',{student_name:student?.name||`${target}번 학생`},'친구에 따라 관계 경험이 다르게 나타나요',`1~2점 ${Math.round(low*100)}% · 4~5점 ${Math.round(high*100)}% · 표준편차 ${sd.toFixed(1)}`,[`수신 관계 응답 ${values.length}건: ${values.join(', ')}점`,`평균 ${(values.reduce((a,b)=>a+b,0)/values.length).toFixed(1)}점 · 표준편차 ${sd.toFixed(1)}`],['친구 집단별 상호작용 차이','활동 상황에 따른 관계 경험 차이','응답 시점의 감정 차이'],'모둠과 놀이 집단에 따라 말투·접근·상대 반응이 달라지는지 확인합니다.')}});
  const checkedPairs=new Set();relationMap.forEach((score,key)=>{const [a,b]=key.split(':').map(Number);const pair=[a,b].sort((x,y)=>x-y).join(':');if(checkedPairs.has(pair))return;checkedPairs.add(pair);const reverse=relationMap.get(`${b}:${a}`);if(reverse!==undefined&&Math.abs(score-reverse)>=2){const aName=classSettings.students.find(row=>Number(row.number)===a)?.name||`${a}번`;const bName=classSettings.students.find(row=>Number(row.number)===b)?.name||`${b}번`;add('watch',{student_name:`${aName} ↔ ${bName}`},'서로 느끼는 관계에 차이가 있어요',`${aName}→${bName} ${score}점 · ${bName}→${aName} ${reverse}점`,[`방향별 관계 점수 차이 ${Math.abs(score-reverse)}점`],['관계 기대의 차이','접근·거절 신호에 대한 이해 차이','응답 시점의 일시적인 감정'],'두 학생을 따로 살펴보고 서로의 접근과 반응을 어떻게 느끼는지 자연스럽게 확인합니다.')}});
  const previousRelationMap=new Map();previous.forEach((item,rater)=>{(payloadOf(item).relationships||[]).forEach(row=>previousRelationMap.set(`${rater}:${Number(row.targetNumber)}`,Number(row.score)))});
  const mutualHighCount=(map,number)=>classSettings.students.filter(student=>Number(student.number)!==number).filter(student=>{const other=Number(student.number);return map.get(`${number}:${other}`)>=4&&map.get(`${other}:${number}`)>=4}).length;
  const positiveMentions=new Map();current.forEach(item=>{const peer=payloadOf(item).peerObservations||{};const text=`${peer.kind?.detail||''} ${peer.growth?.detail||''}`;names.forEach(name=>{if(text.includes(name))positiveMentions.set(name,(positiveMentions.get(name)||0)+1)})});
  classSettings.students.forEach(student=>{const number=Number(student.number);const values=incoming.get(number)||[];if(values.length<4)return;const highCount=values.filter(value=>value>=4).length;const highRatio=highCount/values.length;const mutualNow=mutualHighCount(relationMap,number);const mutualBefore=mutualHighCount(previousRelationMap,number);const unreciprocated=classSettings.students.filter(other=>Number(other.number)!==number).filter(other=>relationMap.get(`${number}:${Number(other.number)}`)>=4&&relationMap.get(`${Number(other.number)}:${number}`)<=2).length;const own=payloadOf(current.get(number));const relationWorry=/친구|관계|혼자|놀/.test(String(own.studentState?.worryDetail||''));const helpCount=new Set((helpMentions.get(student.name)||[]).map(({item})=>Number(item.student_number||payloadOf(item).studentNumber))).size;const relationFlags=[];if(mutualNow<=1)relationFlags.push(`상호 4~5점 연결 ${mutualNow}명`);if(highRatio<=.25)relationFlags.push(`받은 4~5점 ${highCount}/${values.length}건`);if(mutualBefore-mutualNow>=2)relationFlags.push(`상호 높은 연결 ${mutualBefore}→${mutualNow}명`);if(unreciprocated>=2)relationFlags.push(`본인은 높게 평가했지만 되돌아온 점수가 낮은 관계 ${unreciprocated}명`);const contextFlags=[];if(relationWorry)contextFlags.push('본인이 친구 관계 고민을 작성함');if(helpCount>=2)contextFlags.push(`서로 다른 친구 ${helpCount}명이 도움 필요로 언급`);if(relationFlags.length&&relationFlags.length+contextFlags.length>=2){const urgentContext=relationWorry||helpCount>=2||mutualBefore-mutualNow>=2;add(urgentContext?'week':'watch',{student_name:student.name,student_number:number},'관계 연결을 실제 상황에서 확인해 주세요',[...relationFlags,...contextFlags].join(' · '),[...relationFlags,...contextFlags,`수신 관계 점수 ${values.length}건 · 평균 ${(values.reduce((sum,value)=>sum+value,0)/values.length).toFixed(1)}점`],['최근 자리·모둠·놀이 상대의 변화','특정 활동에서만 관계가 이어지는 상황','응답하지 않은 친구와 실제로 친밀할 가능성'],'5일 동안 쉬는 시간 3회와 모둠 활동 2회에서 먼저 접근하는 친구, 상대 반응, 혼자 있는 시간과 참여 기회를 사실 중심으로 기록합니다.')}});
  found.forEach(signal=>{const student=classSettings.students.find(row=>row.name===signal.name);if(!student){signal.protectiveFactors=[];return}const number=Number(student.number);const values=incoming.get(number)||[];const mutual=mutualHighCount(relationMap,number);const positive=positiveMentions.get(student.name)||0;signal.protectiveFactors=[mutual>=2?`상호 높은 관계 ${mutual}명`:null,values.filter(value=>value>=4).length>=2?`받은 4~5점 ${values.filter(value=>value>=4).length}건`:null,positive?`친절·성장 긍정 언급 ${positive}건`:null].filter(Boolean)});
  return found.sort((a,b)=>({urgent:0,week:1,watch:2}[a.type]-{urgent:0,week:1,watch:2}[b.type]));
}
function groupedSignals(filter='all'){const groups=new Map();signals.forEach(signal=>{if(!groups.has(signal.name))groups.set(signal.name,[]);groups.get(signal.name).push(signal)});return[...groups.entries()].map(([name,items])=>{const type=items.some(item=>item.type==='urgent')?'urgent':'watch';const student=classSettings.students.find(row=>row.name===name);const hasPrevious=student&&latestByStudent(allResponses,previousMonth(selectedAnalysisMonth)).has(Number(student.number));const changed=items.some(item=>item.evidence.some(evidence=>String(evidence).includes('→')));const trend=!hasPrevious?'전월 비교 자료 없음':changed?'전월 대비 변화 확인':'이번 달 확인 신호';const protectiveFactors=[...new Set(items.flatMap(item=>item.protectiveFactors||[]))];return{name,items,type,tag:signalTag(type),ids:items.map(item=>item.id),trend,protectiveFactors}}).filter(group=>filter==='all'||group.type===filter).sort((a,b)=>({urgent:0,watch:1}[a.type]-{urgent:0,watch:1}[b.type]))}
function renderAnalysisStatus(){const el=$('#analysisDataStatus');if(!el)return;const current=latestByStudent(allResponses,selectedAnalysisMonth);const total=classSettings.students.length;const submitted=current.size;const rate=total?Math.round(submitted/total*100):0;const monthlyRows=allResponses.filter(item=>monthOf(item)===selectedAnalysisMonth);const duplicateCount=Math.max(0,monthlyRows.length-submitted);const relationshipCount=[...current.values()].filter(item=>(payloadOf(item).relationships||[]).length).length;const relationshipRate=total?Math.round(relationshipCount/total*100):0;const relationshipReady=rate>=80&&relationshipCount>=Math.ceil(total*.8);const concernCounts={친구:0,공부:0,성적:0,등하교:0,가정:0};current.forEach(item=>{const text=String(payloadOf(item).studentState?.worryDetail||'');Object.keys(concernCounts).forEach(key=>{if(text.includes(key))concernCounts[key]++})});const concerns=Object.entries(concernCounts).filter(([,count])=>count).sort((a,b)=>b[1]-a[1]).map(([key,count])=>`${key} ${count}건`).join(' · ')||'분류된 공통 고민 없음';el.className=`notice ${relationshipReady?'safe':'warning'}`;el.innerHTML=`<span>${relationshipReady?'✓':'!'}</span><div><strong>${monthLabel(selectedAnalysisMonth)} 데이터 상태 · 제출 ${submitted}/${total}명 (${rate}%) · 관계 문항 ${relationshipCount}/${total}명 (${relationshipRate}%)</strong><p>학생별 최신 제출을 분석합니다${duplicateCount?` · 추가 제출 ${duplicateCount}건은 최신 응답으로 대체됨`:''}. 관계 구조 분석: <b>${relationshipReady?'참고 가능':'데이터 부족'}</b>${relationshipReady?'':' (제출·관계 문항 응답률 80% 이상 필요)'} · 공통 고민: ${escapeHTML(concerns)}</p></div>`}
function loadClassSettings(){return JSON.parse(JSON.stringify(defaultSettings))}
function persistClassSettings(){localStorage.removeItem('ieum-class-settings');localStorage.removeItem('ieum-teacher-secret');localStorage.removeItem('ieum-observations')}
function syncSignalNames(){}
function renderClassIdentity(){const {teacherName,grade,classNumber}=classSettings;$('#profileAvatar').textContent=teacherName.trim().charAt(0)||'교';$('#profileTeacher').textContent=teacherName?`${teacherName} 선생님`:'담임교사';$('#profileClass').textContent=classSettings.classId?`${grade}학년 ${classNumber}반 담임`:'학급을 연결해 주세요'}
function renderSettings(){const {teacherName,schoolYear,grade,classNumber,classId,students}=classSettings;$('#teacherName').value=teacherName;$('#schoolYear').value=schoolYear;$('#grade').value=grade;$('#classNumber').value=classNumber;$('#classId').value=classId||'';$('#teacherSecret').value='';$('#rosterCount').textContent=`${students.length}명`;$('#rosterBody').innerHTML=students.map((student,index)=>`<tr><td><input type="number" min="1" max="99" value="${student.number}" data-student-number="${index}" aria-label="${index+1}번째 학생 번호"></td><td><input maxlength="20" value="${escapeHTML(student.name)}" data-student-name="${index}" aria-label="${index+1}번째 학생 이름"></td><td><button class="remove-student" type="button" data-remove-student="${index}" aria-label="${escapeHTML(student.name)} 삭제">삭제</button></td></tr>`).join('')}
function collectSettingsForm(){const students=$$('#rosterBody tr').map((row,index)=>({number:Number(row.querySelector('[data-student-number]').value),name:row.querySelector('[data-student-name]').value.trim(),studentId:classSettings.students[index]?.studentId||null,accessCode:classSettings.students[index]?.accessCode||''})).filter(student=>student.name).sort((a,b)=>a.number-b.number);return{teacherName:$('#teacherName').value.trim(),schoolYear:Number($('#schoolYear').value),grade:Number($('#grade').value),classNumber:Number($('#classNumber').value),classId:$('#classId').value.trim(),teacherSecret:$('#teacherSecret').value.trim(),students}}
async function applySettings(){const next=collectSettingsForm();if(!getTeacherSession()){showToast('교사 로그인이 필요합니다.');return false}if(!next.classId||!next.teacherName||!next.students.length){showToast('학급 ID, 교사 이름과 학생을 한 명 이상 입력해 주세요.');return false}try{await teacherRpc('teacher_update_class_context_auth',{p_class_id:next.classId,p_teacher_name:next.teacherName,p_school_year:next.schoolYear,p_grade:next.grade,p_class_number:next.classNumber});await teacherRpc('teacher_sync_roster_auth',{p_class_id:next.classId,p_students:next.students.map(({number,name,studentId})=>({number,name,studentId}))});classSettings={...next,teacherSecret:''};syncSignalNames();renderClassIdentity();renderSettings();renderStudents();renderParticipationLink();renderHomeSignals();renderClassTrend();renderAnalysis($('.filter-tabs .active')?.dataset.filter||'all');renderStudentDetailSelector();showToast('학급 정보와 명단을 DB에 저장했습니다.');return true}catch(error){showToast(`학급 설정 저장 실패: ${error.message}`);return false}}
function renderParticipationLink(){const code=document.querySelector('.copy-row code'),qr=$('#participationQr'),token=classSettings.participationToken;if(!token){if(code)code.textContent='DB 마이그레이션 후 설문 링크가 생성됩니다.';if(qr)qr.innerHTML='<p class="muted">설문 링크 없음</p>';$('#copyLink').dataset.link='';return}const url=new URL('student.html',location.href);url.searchParams.set('join',token);if(code)code.textContent=url.href;$('#copyLink').dataset.link=url.href;if(qr){try{if(typeof qrcode!=='function')throw new Error('QR 라이브러리 로드 실패');const value=qrcode(0,'M');value.addData(url.href);value.make();qr.innerHTML=value.createImgTag(5,8,'학생 설문 QR 코드')}catch(error){qr.innerHTML='<p class="muted">QR 코드를 만들지 못했습니다. 링크를 복사해 주세요.</p>'}}}
function renderResponses(responses){const month=selectedAnalysisMonth||new Date().toISOString().slice(0,7);const monthly=responses.filter(item=>monthOf(item)===month);const submittedNumbers=new Set(monthly.map(item=>Number(item.student_number||payloadOf(item).studentNumber)));const total=classSettings.students.length;const submitted=submittedNumbers.size;const rate=total?Math.round(submitted/total*100):0;$('#studentGrid').innerHTML=classSettings.students.map(student=>`<span class="student-chip ${submittedNumbers.has(Number(student.number))?'':'missing'}">${escapeHTML(student.name)}</span>`).join('');$('#surveyParticipation').textContent=`${submitted} / ${total}명 · ${monthLabel(month)}`;$('#surveyParticipationBar').style.width=`${rate}%`;$('#homeParticipation').innerHTML=`${submitted} <small>/ ${total}명</small>`;$('#homeParticipationBar').style.width=`${rate}%`;$('#homeParticipationText').textContent=`${monthLabel(month)} ${rate}% 참여 · 미제출 ${Math.max(0,total-submitted)}명`;$('#responseList').innerHTML=monthly.length?`<h4>${monthLabel(month)} 제출 원문</h4>`+monthly.map(item=>{const payload=payloadOf(item);const name=item.student_name||payload.studentName||classSettings.students.find(student=>student.number===payload.studentNumber)?.name||'학생';const help=payload.helpNow||'괜찮음';const worry=payload.studentState?.worryDetail||'작성 내용 없음';return`<details><summary><strong>${escapeHTML(name)}</strong><span class="tag ${/바로|즉시/.test(help)?'urgent':/이번 주/.test(help)?'week':'watch'}">${escapeHTML(help)}</span></summary><p>${escapeHTML(worry)}</p></details>`}).join(''):'<p class="muted">선택한 월에 저장된 응답이 없습니다.</p>';renderMonthlySurveyAccordion(responses)}
function renderMonthlySurveyAccordion(responses){const container=$('#monthlySurveyAccordion');if(!container)return;const months=[...new Set(responses.map(monthOf).filter(month=>/^\d{4}-\d{2}$/.test(month)))].sort().reverse();const total=classSettings.students.length;if(!months.length){container.innerHTML='<h4>지난 설문 제출 현황</h4><p class="muted">아직 제출된 설문이 없습니다.</p>';return}container.innerHTML='<h4>지난 설문 제출 현황</h4>'+months.map((month,index)=>{const rows=responses.filter(item=>monthOf(item)===month);const latest=latestByStudent(rows,month);const submitted=[...latest.keys()];const submittedSet=new Set(submitted);const rate=total?Math.round(submitted.length/total*100):0;const missing=classSettings.students.filter(student=>!submittedSet.has(Number(student.number)));const duplicateCount=Math.max(0,rows.length-submitted.length);const submittedNames=classSettings.students.filter(student=>submittedSet.has(Number(student.number))).map(student=>student.name);return`<details><summary><strong>${monthLabel(month)}</strong><span class="tag ${rate>=80?'open':rate?'week':'watch'}">${submitted.length}/${total}명 · ${rate}%</span></summary><div class="evidence-box"><p><strong>제출한 학생 ${submitted.length}명</strong></p><p>${submittedNames.length?submittedNames.map(escapeHTML).join(', '):'없음'}</p><p><strong>아직 제출하지 않은 학생 ${missing.length}명</strong></p><p>${missing.length?missing.map(student=>escapeHTML(student.name)).join(', '):'없음'}</p><p class="muted">제출 기록 ${rows.length}건${duplicateCount?` · 다시 제출한 기록 ${duplicateCount}건`:''}</p><button type="button" class="text-button" data-select-survey-month="${month}">이 달의 응답과 분석 보기 →</button></div></details>`}).join('')}
function normalizeParticipationLabel(){const label=$('#surveyParticipation');if(label)label.textContent=label.textContent.split(' · ')[0];const responseList=$('#responseList');if(responseList)responseList.innerHTML=''}
function applyAnalysisMonth(){signals=analyzeResponses(allResponses,selectedAnalysisMonth);renderResponses(allResponses);normalizeParticipationLabel();renderResponseManagement();renderAnalysisStatus();renderHomeSignals();renderClassTrend();renderClassResponseFlowMetrics();renderAnalysis($('.filter-tabs .active')?.dataset.filter||'all');renderRelationshipsV2();renderRelationshipActions();renderStudentDetailSelector();renderStudentDetail();document.dispatchEvent(new CustomEvent('class-ieum:data-updated'));ensureAiAnalysis()}
async function refreshResponses(showNotice=true){if(!getTeacherSession()){if(showNotice)$('#authDialog').showModal();return}try{allResponses=(await teacherRpc('teacher_get_responses_auth',{p_class_id:classSettings.classId})).map(row=>{const student=row.student_id&&classSettings.students.find(item=>item.studentId===row.student_id);return student?{...row,student_number:student.number,student_name:student.name}:row});await Promise.all([refreshObservations(),refreshGovernance(),refreshSignalReviews()]);updateMonthSelector();applyAnalysisMonth();if(showNotice)showToast('로그인 계정의 응답과 관찰 기록을 불러왔습니다.')}catch(error){showToast(`자료를 불러오지 못했습니다: ${error.message}`)}}
function showToast(message){const el=$('#toast');el.textContent=String(message).replaceAll('AI 관찰 보조','AI 분석');el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2200)}
function handleAuthCallbackNotice(){const query=new URLSearchParams(location.search),fragment=new URLSearchParams(location.hash.replace(/^#/,'')),type=fragment.get('type')||query.get('type'),error=fragment.get('error_description')||query.get('error_description')||fragment.get('error')||query.get('error'),notice=$('#authCallbackNotice');if(!notice)return;if(error){notice.textContent=`이메일 인증에 실패했습니다. ${error.replaceAll('+',' ')}`;notice.className='auth-callback-notice error';notice.hidden=false}else if(type==='recovery'&&fragment.has('access_token')){setTeacherSession({access_token:fragment.get('access_token'),refresh_token:fragment.get('refresh_token'),expires_in:Number(fragment.get('expires_in')||0),token_type:fragment.get('token_type')||'bearer'});notice.textContent='본인 확인이 완료되었습니다. 새 비밀번호를 설정해 주세요.';notice.className='auth-callback-notice success';notice.hidden=false;openAuthDialog('recovery')}else if(type==='signup'||fragment.has('access_token')){notice.textContent='이메일 인증이 완료되었습니다. 가입한 이메일과 비밀번호로 로그인해 주세요.';notice.className='auth-callback-notice success';notice.hidden=false}else return;const clean=new URL(location.href);['type','error','error_code','error_description','code'].forEach(key=>clean.searchParams.delete(key));clean.hash='';history.replaceState(null,document.title,`${clean.pathname}${clean.search}`)}
const signalReviewStatuses={unreviewed:'확인 전',conversation_planned:'대화 예정',fact_checking:'사실 확인 중',support_connected:'지원 연결',no_issue:'특이사항 없음',closed:'종결'};
function signalKey(signal){return [selectedAnalysisMonth,signal.sourceResponseId||signal.submittedAt||'derived',signal.studentNumber||0,signal.type,signal.title].join('|')}
function signalReviewFor(signal){return signalReviews.find(item=>item.signal_key===signalKey(signal))}
async function refreshSignalReviews(){signalReviews=await teacherRpc('teacher_get_signal_reviews_auth',{p_class_id:classSettings.classId})||[]}
function renderSignalInbox(){const inbox=$('#signalReviewInbox');if(!inbox)return;const relevant=signals.filter(signal=>signal.type==='urgent'||signal.type==='week');const resolved=new Set(['support_connected','no_issue','closed']),today=new Date().toISOString().slice(0,10);const statusOf=signal=>signalReviewFor(signal)?.status||'unreviewed';const open=relevant.filter(signal=>!resolved.has(statusOf(signal))),overdue=open.filter(signal=>{const date=signalReviewFor(signal)?.follow_up_date;return date&&date<today});$('#signalReviewCount').textContent=`${open.length}건 확인 필요 · 전체 ${relevant.length}건`;$('#signalReviewUnreviewed').textContent=relevant.filter(signal=>statusOf(signal)==='unreviewed').length;$('#signalReviewInProgress').textContent=relevant.filter(signal=>['conversation_planned','fact_checking'].includes(statusOf(signal))).length;$('#signalReviewOverdue').textContent=overdue.length;$$('[data-signal-review-filter]').forEach(button=>button.classList.toggle('active',button.dataset.signalReviewFilter===signalReviewFilter));const visible=relevant.filter(signal=>signalReviewFilter==='all'||(signalReviewFilter==='open'&&!resolved.has(statusOf(signal)))||(signalReviewFilter==='done'&&resolved.has(statusOf(signal)))).sort((a,b)=>{const aReview=signalReviewFor(a)||{},bReview=signalReviewFor(b)||{};const aOverdue=aReview.follow_up_date&&aReview.follow_up_date<today,bOverdue=bReview.follow_up_date&&bReview.follow_up_date<today;return Number(bOverdue)-Number(aOverdue)||Number(b.type==='urgent')-Number(a.type==='urgent')});if(!visible.length){inbox.innerHTML=`<div class="signal-review-empty"><strong>${relevant.length?'선택한 상태의 신호가 없습니다.':'현재 확인할 안전 신호가 없습니다.'}</strong><p>${relevant.length?'다른 상태 필터를 선택해 주세요.':'선택한 달의 응답에서 담임 확인이 필요한 내용이 생기면 이곳에 표시됩니다.'}</p></div>`;return}inbox.innerHTML=visible.map(signal=>{const review=signalReviewFor(signal)||{},status=review.status||'unreviewed',isOverdue=review.follow_up_date&&review.follow_up_date<today&&!resolved.has(status);return`<article class="signal-review-card ${status==='unreviewed'?'unreviewed':''} ${isOverdue?'overdue':''}" data-signal-key="${escapeHTML(signalKey(signal))}"><header><div><span class="tag ${signal.type}">${escapeHTML(signal.tag)}</span><strong>${escapeHTML(signal.name)}</strong>${isOverdue?'<span class="tag urgent">기한 경과</span>':''}</div><small>${escapeHTML(monthLabel(selectedAnalysisMonth))}</small></header><h3>${escapeHTML(signal.title)}</h3><p>${escapeHTML(signal.summary)}</p><button class="evidence-button signal-source-button" type="button" data-review-evidence="${signal.id}">연결된 근거 확인</button><div class="signal-review-controls"><label><span>확인 상태</span><select data-signal-review-status>${Object.entries(signalReviewStatuses).map(([value,label])=>`<option value="${value}" ${value===status?'selected':''}>${label}</option>`).join('')}</select></label><label><span>후속 확인일</span><input type="date" data-signal-review-date value="${escapeHTML(review.follow_up_date||'')}"></label><label class="signal-review-note"><span>교사 메모</span><input data-signal-review-note maxlength="300" value="${escapeHTML(review.note||'')}" placeholder="확인할 장면이나 다음 조치"></label><button class="primary-button" type="button" data-save-signal-review="${signal.id}">상태 저장</button></div></article>`}).join('')}
function homeStudentLinks(numbers,kind){const rows=[...numbers].map(number=>classSettings.students.find(student=>Number(student.number)===Number(number))).filter(Boolean).sort((a,b)=>Number(a.number)-Number(b.number));return rows.length?rows.map(student=>`<button type="button" class="home-student-link ${kind}" data-open-student="${Number(student.number)}" aria-label="${escapeHTML(student.name)} 학생 살펴보기">${escapeHTML(student.name)}</button>`).join(''):'<span class="home-student-empty">해당 학생 없음</span>'}
function renderHomeSignals(){const urgentStudents=new Set(signals.filter(signal=>signal.type==='urgent'&&signal.studentNumber).map(signal=>Number(signal.studentNumber)));const observationStudents=new Set(signals.filter(signal=>signal.type!=='urgent'&&signal.studentNumber).map(signal=>Number(signal.studentNumber)));urgentStudents.forEach(number=>observationStudents.delete(number));const latest=latestByStudent(allResponses,selectedAnalysisMonth);const positive=[...latest.values()].filter(item=>{const peer=payloadOf(item).peerObservations||{};return peer.kind?.detail||peer.growth?.detail}).length;$('#homeUrgent').innerHTML=`${urgentStudents.size} <small>명</small>`;$('#homeWeek').innerHTML=`${observationStudents.size} <small>명</small>`;$('#homeUrgentStudents').innerHTML=homeStudentLinks(urgentStudents,'urgent');$('#homeWeekStudents').innerHTML=homeStudentLinks(observationStudents,'watch');$('#homePositive').innerHTML=`${positive} <small>건</small>`;renderSignalInbox()}
function classMonthlyTrend(responses){const byMonth=new Map();responses.filter(item=>!item.analysis_excluded).forEach(item=>{const month=monthOf(item),number=Number(item.student_number||payloadOf(item).studentNumber);if(!/^\d{4}-\d{2}$/.test(month)||!number)return;if(!byMonth.has(month))byMonth.set(month,new Map());const current=byMonth.get(month).get(number),time=new Date(item.submitted_at||payloadOf(item).submittedAt||0);if(!current||time>current.time)byMonth.get(month).set(number,{item,time})});return[...byMonth.entries()].sort(([a],[b])=>a.localeCompare(b)).slice(-6).map(([month,students])=>{const scores=[];students.forEach(({item})=>Object.values(payloadOf(item).selfRatings||{}).forEach(value=>{const score=Number(value?.score??value);if(score>=1&&score<=5)scores.push(score)}));return{month,participants:students.size,rate:classSettings.students.length?Math.round(students.size/classSettings.students.length*100):0,average:scores.length?scores.reduce((sum,value)=>sum+value,0)/scores.length:null}})}
function renderClassTrend(){const chart=$('#classTrendChart'),confidence=$('#classTrendConfidence'),insight=$('#classTrendInsight');if(!chart||!confidence||!insight)return;const trend=classMonthlyTrend(allResponses);if(!trend.length){confidence.textContent='등록 자료 0건';chart.innerHTML='<p class="muted class-trend-empty">설문이 제출되면 월별 실제 평균이 표시됩니다.</p>';insight.innerHTML='<span>ⓘ</span><p><strong>아직 비교할 자료가 없습니다.</strong><br>미제출과 분석 제외 응답은 평균에 포함하지 않습니다.</p>';return}confidence.textContent=`최근 ${trend.length}개월 · ${trend.at(-1).rate}% 참여`;chart.innerHTML=`<div class="chart-line">${trend.map((row,index)=>`<span class="${index===trend.length-1?'current':''}" style="height:${row.average?Math.max(12,row.average/5*82):8}%"><b>${row.average?row.average.toFixed(1):'—'}</b><small>${row.participants}명</small></span>`).join('')}</div><div class="chart-labels">${trend.map(row=>`<span>${Number(row.month.slice(5))}월</span>`).join('')}</div>`;const latest=trend.at(-1),before=trend.at(-2);if(!before||latest.average===null||before.average===null){insight.innerHTML=`<span>ⓘ</span><p><strong>${monthLabel(latest.month)} 실제 응답 ${latest.participants}명</strong><br>다음 달 자료가 쌓이면 변화 폭을 비교합니다.</p>`;return}const delta=latest.average-before.average,direction=Math.abs(delta)<.05?'비슷합니다':delta>0?'높아졌습니다':'낮아졌습니다';insight.innerHTML=`<span>${Math.abs(delta)<.05?'→':delta>0?'↗':'↘'}</span><p><strong>학급 자기평가 평균이 지난달보다 ${Math.abs(delta).toFixed(1)}점 ${direction}</strong><br>${before.participants}명과 ${latest.participants}명의 실제 제출 자료를 비교했습니다. 참여 학생 구성이 다를 수 있어 관찰과 함께 해석하세요.</p>`}
function renderAnalysis(filter='all'){const container=$('#analysisCards');if(!container)return;const allGroups=groupedSignals();const counts={all:allGroups.length,urgent:allGroups.filter(group=>group.type==='urgent').length,watch:allGroups.filter(group=>group.type==='watch').length};$$('.filter-tabs button').forEach(button=>{const labels={all:'전체',urgent:'즉시 확인',watch:'지속 관찰'};button.textContent=`${labels[button.dataset.filter]} ${counts[button.dataset.filter]}`});const visible=groupedSignals(filter);container.innerHTML=visible.length?visible.map(group=>{const evidenceCount=group.items.reduce((sum,item)=>sum+item.evidence.length,0);return`<article class="analysis-card" data-type="${group.type}"><header><div><div class="analysis-card-tags"><span class="tag ${group.type}">${group.tag}</span><span class="change-badge">${escapeHTML(group.trend)}</span></div><h3>${escapeHTML(group.name)} · 통합 확인 카드</h3><div class="signal-summary">${group.items.map(item=>`<p><strong>▣ ${escapeHTML(item.title)}</strong><br>${escapeHTML(item.summary)}</p>`).join('')}</div>${group.protectiveFactors.length?`<div class="protective-factors"><strong>긍정적 보호요인</strong><p>${group.protectiveFactors.map(item=>`✓ ${escapeHTML(item)}`).join(' · ')}</p></div>`:''}</div></header><footer><span class="evidence-count">신호 ${group.items.length}개 · 근거 ${evidenceCount}개</span><button class="evidence-button" data-evidence-group="${group.ids.join(',')}">통합 근거와 관찰 제안</button></footer></article>`}).join(''):'<div class="panel"><p class="muted">선택한 조건에 해당하는 실제 응답 신호가 없습니다.</p></div>'}
function aiTeacherDisplayText(value){return String(value||'').replace(/학생-(\d+)|(\d+)번 학생/g,(match,anonymousNumber,numberLabel)=>{const number=Number(anonymousNumber||numberLabel),name=classSettings.students.find(student=>Number(student.number)===number)?.name;return name||match}).replace(/학생\s+학생/g,'학생')}
function cleanAiEvidenceText(value){return aiTeacherDisplayText(String(value||'').replace(/^\[(계산 결과|학생 원문|친구 관찰)\]\s*/,''))}
function aiEvidenceHTML(value,display){const text=String(value||''),match=text.match(/^\[(계산 결과|학생 원문|친구 관찰)\]\s*(.*)$/);return match?`<span class="ai-evidence-row"><b>${escapeHTML(match[1])}</b>${display(match[2])}</span>`:`<span class="ai-evidence-row"><b>기존 근거</b>${display(text)}</span>`}
function formatAnalysisTimestamp(value){const date=new Date(value||'');return Number.isNaN(date.getTime())?'시각 정보 없음':new Intl.DateTimeFormat('ko-KR',{timeZone:'Asia/Seoul',year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false}).format(date)}
function classResponseFlowData(){const current=latestByStudent(allResponses,selectedAnalysisMonth),total=classSettings.students.length,ratings=[],relationships=[];let conversationRequests=0;current.forEach(item=>{const payload=payloadOf(item),state=payload.studentState||{};Object.values(payload.selfRatings||{}).forEach(row=>{const score=Number(row?.score);if(score>0)ratings.push(score)});(payload.relationships||[]).forEach(row=>{const score=Number(row.score);if(score>0)relationships.push(score)});if(String(state.teacherWish||'').trim())conversationRequests++});const immediateStudents=new Set(signals.filter(item=>item.type==='urgent').map(item=>item.student_name));return{submitted:current.size,total,rate:total?Math.round(current.size/total*100):0,selfAverage:ratings.length?(ratings.reduce((sum,value)=>sum+value,0)/ratings.length).toFixed(1):'—',relationshipAverage:relationships.length?(relationships.reduce((sum,value)=>sum+value,0)/relationships.length).toFixed(1):'—',conversationRequests,immediate:immediateStudents.size}}
function renderClassResponseFlowMetrics(){const target=$('#classResponseFlowMetrics');if(!target)return;const data=classResponseFlowData();target.innerHTML=`<article><span>설문 참여</span><strong>${data.submitted} / ${data.total}명</strong><small>${data.rate}% 참여</small></article><article><span>학교생활 자기평가</span><strong>${data.selfAverage} / 5</strong><small>선택한 달 평균</small></article><article><span>친구 관계 응답</span><strong>${data.relationshipAverage} / 5</strong><small>작성된 점수 평균</small></article><article><span>교사와 대화 희망</span><strong>${data.conversationRequests}명</strong><small>듣고 싶은 말을 작성함</small></article><article><span>바로 확인할 응답</span><strong>${data.immediate}명</strong><small>즉시 확인 신호 기준</small></article>`}
function anonymousClassSummaryText(value){let result=String(cleanAiEvidenceText(value)||'').replace(/학생-\d+/g,'개별 학생').replace(/\d+번 학생/g,'개별 학생');classSettings.students.forEach(student=>{const name=String(student.name||'').trim();if(name)result=result.split(name).join('개별 학생')});return result}
function renderClassObservationPatterns(patterns){const target=$('#classObservationPatterns');if(!target)return;renderClassResponseFlowMetrics();const show=value=>escapeHTML(anonymousClassSummaryText(value));target.innerHTML=`<div class="class-flow-summary-head"><h4>AI 학급 요약</h4><span>학생 이름 없이 학급 전체 흐름만 요약합니다.</span></div>${patterns.length?`<div class="class-observation-patterns">${patterns.slice(0,3).map(item=>`<article class="ai-result-card class-pattern-card"><p><strong>눈에 띄는 변화</strong><br>${show(item.pattern)}</p><p class="class-pattern-evidence"><strong>함께 확인할 응답</strong><br>${(item.evidence||[]).map(value=>show(value)).join('<br>')}</p><p class="class-pattern-coaching"><strong>이번 달 학급 운영 참고</strong><br>${show(item.teacher_check)}</p></article>`).join('')}</div>`:'<div class="ai-no-priority"><strong>이번 달에 공통으로 두드러진 흐름은 없습니다.</strong><p>현재 응답에서 여러 학생에게 공통으로 나타난 내용이 충분하지 않습니다.</p></div>'}`}
function renderAiAnalysis(result){const content=$('#aiAnalysisContent'),analysis=result.analysis||{},meta=result.meta||{},display=value=>escapeHTML(aiTeacherDisplayText(value)),list=(items,mark='•')=>(items||[]).map(value=>`${mark} ${display(value)}`).join('<br>');currentAiAnalysis=result;currentAiRun={id:meta.runId||result.id||null,status:meta.reviewStatus||'active'};$('#aiAnalysisMeta').textContent=`마지막 분석 ${formatAnalysisTimestamp(meta.generatedAt)} · ${monthLabel(meta.month||selectedAnalysisMonth)} · ${meta.responseCount||0}명 · ${meta.cached?'저장 결과':'새 분석'} · ${meta.model||'AI'} · ${meta.analysisVersion||'버전 확인 불가'}`;const priority=(analysis.priority_students||[]).slice(0,3),patterns=analysis.class_patterns||[],judgment=analysis.overall_judgment||analysis.summary||'종합 판단이 없습니다.';renderClassObservationPatterns(patterns);content.innerHTML=`<section class="ai-overall-judgment"><p class="eyebrow">AI 학생 지원 요약</p><p class="ai-summary">${display(judgment)}</p></section><div class="ai-priority-heading"><h4>먼저 살펴볼 학생 ${priority.length}명</h4><span>응답에서 살펴볼 점 · 확인할 장면 · 학생 코칭 · 다음 지원 방향</span></div><div class="ai-priority-grid">${priority.length?priority.map((item,index)=>{const observations=(item.observation_points||[]).slice(0,2),directions=(item.coaching_directions||(item.coaching_direction?[item.coaching_direction]:[])).slice(0,2),questions=(item.coaching_questions||item.teacher_checks||[]).slice(0,2);return`<article class="ai-result-card teacher-action-card"><div class="ai-student-rank"><div><span class="tag ${item.priority==='즉시 확인'?'urgent':'watch'}">${display(item.priority)}</span><h4>${display(item.student)}</h4></div></div><div class="ai-student-support-grid"><section class="ai-attention-reason"><strong>응답에서 살펴볼 점</strong><p>${display(item.attention_reason||(item.possible_interpretations||[])[0]||'연결된 근거를 실제 상황에서 확인해 주세요.')}</p>${(item.protective_factors||[]).length?`<p class="ai-protective-inline"><b>함께 볼 긍정 요소</b> ${list(item.protective_factors.slice(0,2),'✓')}</p>`:''}</section><section><strong>담임이 확인할 장면</strong><div class="ai-observation-points">${observations.length?observations.map(point=>`<article><b>${display(point.context)}</b><span>${display(point.behavior)}</span><small>${display(point.period)}</small></article>`).join(''):`<p>${list((item.teacher_checks||[]).slice(0,2),'✓')||'구체적인 장면과 행동을 사실 중심으로 확인해 주세요.'}</p>`}</div></section><section class="ai-coaching-questions"><strong>학생 코칭</strong><p>${questions.length?list(questions,'“'):'학생의 선택을 존중하는 말로 현재 상황을 물어보세요.'}</p></section><section class="coaching-direction"><strong>다음 지원 방향</strong><p>${list(directions,'→')}</p></section></div>${(item.avoid_actions||[]).length?`<section class="ai-avoid-actions"><strong>피하면 좋은 대응</strong><p>${list(item.avoid_actions.slice(0,2),'!')}</p></section>`:''}<details class="ai-evidence-details"><summary>필요할 때 응답 원문 확인</summary><p class="muted">응답 원문은 해석을 확인할 때만 펼쳐 보세요.</p><div class="ai-evidence-list">${(item.evidence||[]).map(value=>aiEvidenceHTML(value,display)).join('')}</div><button type="button" class="text-button" data-ai-source-index="${index}">연결된 응답 원문 보기</button></details></article>`}).join(''):'<div class="ai-no-priority"><strong>먼저 살펴볼 학생이 따로 없습니다</strong><p>현재 입력에서 의미 있는 복수 신호가 충분하지 않습니다. 일반적인 학급 관찰은 계속해 주세요.</p></div>'}</div><details class="ai-limitations"><summary>결과를 볼 때 참고할 점</summary><p>${list(analysis.limitations)||'AI 결과는 실제 관찰을 대신하지 않습니다.'}</p></details>`}
async function runAiAnalysis(force=false){const button=force?$('#rerunAiAnalysis'):$('#runAiAnalysis');if(!getTeacherSession()){showToast('교사 로그인이 필요합니다.');$('#authDialog').showModal();return}if(force&&!confirm('저장 결과를 사용하지 않고 AI를 새로 호출할까요? 월별 호출 한도에 포함됩니다.'))return;button.disabled=true;const label=button.textContent;button.textContent='안전하게 분석 중…';try{const result=await teacherEdgeFunction('analyze-class',{classId:classSettings.classId,month:selectedAnalysisMonth,force});renderAiAnalysis(result);showToast(result.meta?.cached?'저장된 AI 분석을 불러왔습니다.':'새 AI 분석을 저장했습니다.')}catch(error){showToast(`AI 분석 실패: ${error.message}`)}finally{button.disabled=false;button.textContent=label}}
async function ensureAiAnalysis(){const key=`${classSettings.classId}:${selectedAnalysisMonth}`;if(!getTeacherSession()||!classSettings.classId||!allResponses.some(item=>monthOf(item)===selectedAnalysisMonth)||aiAutoKey===key)return;aiAutoKey=key;$('#aiAnalysisMeta').textContent='자동 분석 중…';$('#aiAnalysisContent').innerHTML='<p class="muted">저장된 결과를 확인하고 있습니다.</p>';try{const result=await teacherEdgeFunction('analyze-class',{classId:classSettings.classId,month:selectedAnalysisMonth,force:false});renderAiAnalysis(result)}catch(error){aiAutoKey='';$('#aiAnalysisMeta').textContent='분석을 불러오지 못함';$('#aiAnalysisContent').innerHTML=`<p class="muted">${escapeHTML(error.message)} · 위의 AI 분석 버튼으로 다시 시도해 주세요.</p>`}}
