const evidenceFieldLabels={helpNow:'즉시 도움 요청',studentState:{worryDetail:'학교생활 고민',teacherWish:'선생님께 듣고 싶은 말'},peerObservations:{kind:{detail:'친절·존중 친구'},growth:{detail:'긍정적 변화 친구'},hurt:{detail:'상처를 준 말과 행동'},needsHelp:{detail:'도움이 필요한 친구'}},unresolved:{detail:'속상한 마음이 남은 관계'}};
function valueAtPath(object,path){return String(path).split('.').reduce((value,key)=>value?.[key],object)}
function labelAtPath(path){return String(path).split('.').reduce((value,key)=>value?.[key],evidenceFieldLabels)||path}
function openAiSourceEvidence(item){const refs=(item.source_refs||[]).map(ref=>{const [responseId,...fieldParts]=String(ref).split('|'),field=fieldParts.join('|'),response=allResponses.find(row=>String(row.id)===responseId);return response?{response,field,value:valueAtPath(payloadOf(response),field)}:null}).filter(row=>row?.value);if(!refs.length){const number=Number(String(item.student||'').replace(/\D/g,'')),fallback=latestByStudent(allResponses,selectedAnalysisMonth).get(number);if(fallback)refs.push({response:fallback,field:'studentState.worryDetail',value:payloadOf(fallback).studentState?.worryDetail||'선택한 학생의 최신 설문 응답'})}$('#dialogTitle').textContent=`${aiTeacherDisplayText(item.student)} · 근거 원문`;$('#dialogContent').innerHTML=refs.length?refs.map(({response,field,value})=>`<article class="source-evidence"><div><span class="tag open">${escapeHTML(labelAtPath(field))}</span><small>${escapeHTML(monthLabel(monthOf(response)))} · ${new Date(response.submitted_at).toLocaleString('ko-KR')}</small></div><p>${escapeHTML(value)}</p></article>`).join('')+'<div class="notice warning"><span>!</span><p>원문은 학생이 작성한 내용입니다. 사실 판정이 아니라 관찰과 대화를 위한 근거로 확인하세요.</p></div>':'<p class="muted">연결된 원문을 찾지 못했습니다. 이전 형식의 저장 결과라면 새로 분석해 주세요.</p>';delete $('#saveObservation').dataset.signal;delete $('#saveObservation').dataset.signalGroup;$('#saveObservation').hidden=true;$('#evidenceDialog').showModal()}
function attachAiSourceButtons(){const priority=currentAiAnalysis?.analysis?.priority_students||[];$$('#aiAnalysisContent .ai-result-card').slice(0,priority.length).forEach((card,index)=>{if(card.querySelector('[data-ai-source-index]'))return;const button=document.createElement('button');button.type='button';button.className='secondary-button ai-source-button';button.dataset.aiSourceIndex=String(index);button.textContent='근거 원문 보기';card.append(button)})}
