function renderStudents(){renderResponses([])}
function studentMonthlyResponses(studentNumber){const months=[...new Set(allResponses.map(monthOf).filter(month=>/^\d{4}-\d{2}$/.test(month)))].sort();return months.map(month=>({month,item:latestByStudent(allResponses,month).get(Number(studentNumber))})).filter(row=>row.item)}
function updateStudentStepButtons(){const select=$('#studentDetailSelect'),selected=Number(select?.value),index=classSettings.students.findIndex(student=>Number(student.number)===selected),previous=$('#previousStudent'),next=$('#nextStudent');if(previous)previous.disabled=index<=0;if(next)next.disabled=index<0||index>=classSettings.students.length-1}
function renderStudentDetailSelector(){const select=$('#studentDetailSelect');if(!select)return;const previous=Number(select.value),selected=classSettings.students.some(student=>Number(student.number)===previous)?previous:0;select.innerHTML='<option value="">학생을 선택해 주세요</option>'+classSettings.students.map(student=>`<option value="${Number(student.number)}" ${Number(student.number)===selected?'selected':''}>${Number(student.number)}번 ${escapeHTML(student.name)} 학생</option>`).join('');const printButton=$('#printStudentReport');if(printButton)printButton.disabled=!selected;$$('[data-student-detail-tab]').forEach(button=>button.disabled=!selected);updateStudentStepButtons()}
function moveStudentDetail(direction){const select=$('#studentDetailSelect'),index=classSettings.students.findIndex(student=>Number(student.number)===Number(select?.value)),nextIndex=index+direction;if(!select||index<0||nextIndex<0||nextIndex>=classSettings.students.length)return;select.value=String(classSettings.students[nextIndex].number);select.dispatchEvent(new Event('change',{bubbles:true}));select.focus()}
let activeStudentDetailTab='summary';
function mentionsStudentName(text,student){const value=String(text||'').trim(),name=String(student?.name||'').trim();if(!name||!value.includes(name))return false;return !classSettings.students.some(other=>Number(other.number)!==Number(student.number)&&String(other.name||'').length>name.length&&String(other.name).includes(name)&&value.includes(other.name))}
function receivedPositiveMentions(student,month){const mentions=[];latestByStudent(allResponses,month).forEach((item,reporter)=>{if(reporter===Number(student.number))return;const peer=payloadOf(item).peerObservations||{};[['친절·존중',peer.kind],['성장',peer.growth]].forEach(([type,response])=>{const text=String(response?.detail||'').trim(),selected=(response?.studentNumbers||[]).map(Number),matched=selected.length?selected.includes(Number(student.number)):mentionsStudentName(text,student);if(matched)mentions.push({type,text:text||'이름 선택 응답',reporter:item.student_name||payloadOf(item).studentName||`${reporter}번`,structured:selected.length>0})})});return mentions}
function incomingRelationshipFor(studentNumber,month){const values=[];latestByStudent(allResponses,month).forEach((item,rater)=>{if(rater===Number(studentNumber))return;const row=(payloadOf(item).relationships||[]).find(entry=>Number(entry.targetNumber)===Number(studentNumber));if(row&&Number(row.score)>0)values.push(Number(row.score))});return values.length?{average:values.reduce((sum,value)=>sum+value,0)/values.length,count:values.length}:null}
function studentOpenSupportSummary(student){const matches=item=>(student.studentId&&item.student_id===student.studentId)||Number(item.student_number||item.studentNumber)===Number(student.number),openReviews=signalReviews.filter(item=>matches(item)&&!['support_connected','no_issue','closed'].includes(item.status)),openObservations=getObservations().filter(item=>matches(item)&&item.status!=='done'),dates=[...openReviews.map(item=>item.follow_up_date),...openObservations.map(item=>item.followUpDate)].filter(Boolean).sort();return{count:openReviews.length+openObservations.length,nextDate:dates[0]||'',missingDate:openReviews.concat(openObservations).some(item=>!(item.follow_up_date||item.followUpDate))}}
function studentResponseInsights(student,monthly){
  const latestRow=monthly.at(-1),previousRow=monthly.at(-2),month=latestRow.month,incoming=incomingRelationshipFor(student.number,month),positiveCount=receivedPositiveMentions(student,month).length,summary=[],changes=[];
  summary.push({tone:'data',title:'친구 관계 점수 평균',body:incoming?`${monthLabel(month)} 친구 ${incoming.count}명이 준 관계 점수의 평균은 ${incoming.average.toFixed(1)}점 / 5점입니다.`:`${monthLabel(month)} 비교할 수 있는 친구 관계 점수 응답이 없습니다.`});
  summary.push({tone:'safe',title:'긍정적인 친구 언급',body:`친구들이 작성한 ‘친절·존중 친구’와 ‘긍정적 변화 친구’ 서술에서 이 학생의 이름이 ${monthLabel(month)} ${positiveCount}건 확인되었습니다. 고마운 학생이나 나아진 학생을 판정한 수치가 아니라 이름이 포함된 응답 건수입니다.`});
  if(!previousRow){changes.push({tone:'safe',title:'아직 전월 비교 자료가 없습니다',body:`${monthLabel(month)} 관계 응답을 첫 기준으로 저장했습니다. 다음 제출부터 변화를 비교합니다.`})}else{
    const previousIncoming=incomingRelationshipFor(student.number,previousRow.month);if(incoming&&previousIncoming&&Math.abs(incoming.average-previousIncoming.average)>=.5)changes.push({tone:'watch',title:'친구 관계 점수 평균 변화',body:`평균 ${previousIncoming.average.toFixed(1)}점에서 ${incoming.average.toFixed(1)}점으로 ${(incoming.average-previousIncoming.average)>0?'높아졌습니다':'낮아졌습니다'}(${monthLabel(previousRow.month)}과 비교).`});
    const previousPositive=receivedPositiveMentions(student,previousRow.month).length;if(positiveCount!==previousPositive)changes.push({tone:'data',title:'친절·성장 문항 이름 언급 변화',body:`친절·존중 및 긍정적 변화 문항의 이름 언급이 ${previousPositive}건에서 ${positiveCount}건으로 바뀌었습니다.`});
    if(!changes.length)changes.push({tone:'safe',title:'지난 제출과 비교해 큰 변화가 없습니다',body:`${monthLabel(previousRow.month)}과 비교해 친구들이 준 관계 점수 평균 0.5점 이상의 변화나 친절·성장 문항 이름 언급 건수 변화가 나타나지 않았습니다.`})
  }
  const state=!incoming?'관계 응답 없음':!previousRow?'비교 자료 없음':changes.some(item=>item.tone==='watch'||item.tone==='data')?'변화 확인':'큰 변화 없음';
  return{month,summary,changes,state}
}
function studentResponseInsightHTML(student,monthly){const insight=studentResponseInsights(student,monthly),cards=items=>items.map(item=>`<article class="student-insight-card ${item.tone}"><h4>${escapeHTML(item.title)}</h4><p>${escapeHTML(item.body)}</p></article>`).join('');return`<section class="panel student-response-insight"><div class="panel-head"><div><p class="eyebrow">${monthLabel(insight.month)} 기준</p><h3>지난 응답과 비교</h3></div><span class="confidence ${insight.state==='큰 변화 없음'?'good':''}">${escapeHTML(insight.state)}</span></div><div class="student-insight-grid">${cards(insight.changes)}</div><p class="muted student-insight-note">현재 값은 위 요약에서 확인하고, 여기서는 지난 응답과 달라진 관계 응답만 표시합니다.</p></section>`}
