async function refreshPilotMetrics(){const container=$('#pilotMetrics');if(!container||!getTeacherSession()||!classSettings.classId)return;try{const rows=await teacherRpc('teacher_get_pilot_metrics_auth',{p_class_id:classSettings.classId}),data=rows?.[0]||rows||{},reviewRate=Number(data.ai_recommendation_count)?Math.round(Number(data.ai_review_count)/Number(data.ai_run_count||1)*100):0,doneRate=Number(data.observation_count)?Math.round(Number(data.observation_done_count)/Number(data.observation_count)*100):0;container.innerHTML=`<div class="pilot-metric-head"><div><p class="eyebrow">실제 운영 측정</p><h4>${data.latest_month?monthLabel(String(data.latest_month).slice(0,7)):'설문 자료 없음'} 파일럿 지표</h4></div><span class="confidence">학생 순위로 사용하지 않음</span></div><div class="pilot-metric-grid"><article><span>최근 참여율</span><strong>${Number(data.latest_participation_rate)||0}%</strong><small>${Number(data.latest_participants)||0}/${Number(data.roster_count)||0}명</small></article><article><span>평균 작성 시간</span><strong>${formatDuration(data.average_completion_seconds)}</strong><small>새 제출부터 측정</small></article><article><span>AI 추천·평가</span><strong>${Number(data.ai_recommendation_count)||0}건 · ${Number(data.ai_review_count)||0}회</strong><small>분석 평가 기록 ${reviewRate}%</small></article><article><span>관찰 확인</span><strong>${Number(data.observation_done_count)||0}/${Number(data.observation_count)||0}건</strong><small>${doneRate}% 완료</small></article><article><span>지원 연결</span><strong>${Number(data.observation_support_count)||0}건</strong><small>교사 확인 결과</small></article><article><span>특이사항 없음</span><strong>${Number(data.observation_no_issue_count)||0}건</strong><small>확인 후 종결</small></article></div>`}catch(error){container.innerHTML=`<p class="muted">파일럿 측정 마이그레이션 적용 후 지표가 표시됩니다: ${escapeHTML(error.message)}</p>`}}
async function refreshPilotReadiness(){const container=$('#pilotChecklist'),summary=$('#pilotReadinessSummary');if(!container||!summary||!getTeacherSession()||!classSettings.classId)return;summary.className='pilot-readiness-summary';summary.innerHTML='<strong>점검 중</strong><span>배포·인증·학급 자료 상태를 확인하고 있습니다.</span>';try{const rows=await teacherRpc('teacher_get_pilot_readiness_auth',{p_class_id:classSettings.classId}),data=rows?.[0]||rows||{},session=getTeacherSession(),secureOrigin=location.protocol==='https:'||location.hostname==='localhost',wideEnough=window.innerWidth>=360,sessionAvailable=typeof sessionStorage!=='undefined',canvasAvailable=!!document.createElement('canvas').getContext,downloadAvailable='download' in document.createElement('a'),checks=[['보안 연결',secureOrigin,secureOrigin?'HTTPS 배포 주소 사용':'HTTPS Pages 주소에서 실행 필요'],['태블릿 화면 크기',wideEnough,`${window.innerWidth}×${window.innerHeight}px ${wideEnough?'사용 가능':'가로 360px 이상 권장'}`],['임시 저장공간',sessionAvailable,sessionAvailable?'브라우저 창 단위 임시 저장 가능':'다른 브라우저 사용 필요'],['QR·PDF 파일 기능',canvasAvailable&&downloadAvailable,canvasAvailable&&downloadAvailable?'캔버스와 파일 다운로드 지원':'브라우저 업데이트 필요'],['교사 로그인 자동 갱신',!!session?.refresh_token,session?.refresh_token?'세션 갱신 가능':'다시 로그인해 갱신 토큰 발급 필요'],['DB·학급 권한',true,'담당 학급 점검 함수 응답 정상'],['안전한 학생 참여 링크',!!data.has_participation_token,data.has_participation_token?'임의 토큰 적용':'3차 DB 마이그레이션 필요'],['학생 명단',Number(data.student_count)>0,`${Number(data.student_count)||0}명 등록`],['월별 실제 설문',Number(data.response_months)>=2,`${Number(data.response_months)||0}개월 자료`],['참여율 안전장치',Number(data.latest_participation_rate)>=80,`최근 월 ${Number(data.latest_participation_rate)||0}%`],['관찰·후속 기록',Number(data.observation_count)>0,`${Number(data.observation_count)||0}건`],['AI 저장 결과',Number(data.ai_complete_count)>0,`${Number(data.ai_complete_count)||0}건`],['최근 백업',!!data.last_backup_at,data.last_backup_at?new Date(data.last_backup_at).toLocaleString('ko-KR'):'백업 이력 없음']],readyCount=checks.filter(([,ok])=>ok).length,pendingCount=checks.length-readyCount;container.innerHTML=checks.map(([label,ok,detail])=>`<article class="pilot-check ${ok?'ready':'pending'}"><span>${ok?'✓':'!'}</span><div><strong>${escapeHTML(label)}</strong><p>${escapeHTML(detail)}</p></div></article>`).join('');summary.className=`pilot-readiness-summary ${pendingCount?'pending':'ready'}`;summary.innerHTML=`<strong>${readyCount}/${checks.length}개 준비</strong><span>${pendingCount?`확인이 필요한 항목 ${pendingCount}개가 있습니다.`:'기술 점검 항목이 모두 준비되었습니다.'} · ${new Date().toLocaleString('ko-KR')}</span>`}catch(error){summary.className='pilot-readiness-summary error';summary.innerHTML=`<strong>점검 실패</strong><span>${escapeHTML(error.message)}</span>`;container.innerHTML='<p class="muted">로그인 상태와 DB 마이그레이션 적용 여부를 확인해 주세요.</p>'}}
