function buildAiReportSection(scope,selectedNumber,includeNames){const analysis=currentAiAnalysis?.analysis||{},show=value=>escapeHTML(includeNames?aiTeacherDisplayText(value):value),list=(items,mark='•')=>(items||[]).map(value=>`${mark} ${show(value)}`).join('<br>'),allPriority=(analysis.priority_students||[]).slice(0,3),priority=scope==='student'?allPriority.filter(item=>item.student===`학생-${selectedNumber}`):allPriority,patterns=scope==='class'?(analysis.class_patterns||[]):[],judgment=analysis.overall_judgment||analysis.summary||'AI 종합 판단이 없습니다.';return`<section class="pdf-ai-section"><div class="pdf-block pdf-section-heading"><h2>AI 학생 지원</h2><h3>학생 지원 요약</h3><p>${show(judgment)}</p></div><div class="pdf-block pdf-section-heading"><h3>먼저 살펴볼 학생 ${priority.length}명</h3></div>${priority.length?priority.map(item=>{const observations=item.observation_points||[],directions=item.coaching_directions||(item.coaching_direction?[item.coaching_direction]:[]),questions=item.coaching_questions||item.teacher_checks||[];return`<article class="pdf-block pdf-student-card"><h4>${show(item.student)} · ${show(item.priority)}</h4><p><b>응답에서 살펴볼 점</b><br>${show(item.attention_reason||(item.possible_interpretations||[])[0]||'실제 상황 확인이 필요합니다.')}</p><p><b>담임이 확인할 장면</b><br>${observations.length?observations.map(point=>`• ${show(point.context)} · ${show(point.behavior)} · ${show(point.period)}`).join('<br>'):list(item.teacher_checks||[],'✓')}</p>${questions.length?`<p><b>학생 코칭</b><br>${list(questions,'“')}</p>`:''}<p><b>다음 지원 방향</b><br>${list(directions,'→')}</p></article>`}).join(''):'<p class="pdf-block">이 범위에서 먼저 살펴볼 학생이 따로 없습니다.</p>'}${patterns.length?`<div class="pdf-block pdf-section-heading"><h3>우리 반 응답 흐름 · AI 학급 요약</h3></div>${patterns.map(item=>`<article class="pdf-block pdf-pattern-card"><h4>${show(item.pattern)}</h4><p><b>함께 확인할 응답</b><br>${(item.evidence||[]).map(value=>show(cleanAiEvidenceText(value))).join('<br>')}</p><p><b>이번 달 학급 운영 참고</b><br>${show(item.teacher_check)}</p></article>`).join('')}`:''}<div class="pdf-block pdf-limitations"><h3>결과를 볼 때 참고할 점</h3><p>${list(analysis.limitations)||'AI 결과는 실제 관찰을 대신하지 않습니다.'}</p></div></section>`}
async function downloadPdfDocument(content,fileName){if(typeof html2canvas!=='function'||!window.jspdf?.jsPDF)throw new Error('PDF 구성 요소를 불러오지 못했습니다. 새로고침 후 다시 시도해 주세요.');const root=document.createElement('section');root.className='pdf-render-root';root.innerHTML=content;document.body.append(root);try{if(document.fonts?.ready)await document.fonts.ready;const{jsPDF}=window.jspdf,pdf=new jsPDF({orientation:'portrait',unit:'mm',format:'a4',compress:true}),margin=16,pageWidth=210,pageHeight=297,contentWidth=pageWidth-margin*2,footerY=289,maxY=footerY-8,usableHeight=maxY-margin,blocks=[...root.children].flatMap(child=>child.classList.contains('pdf-ai-section')?[...child.querySelectorAll('.pdf-block')]:[child]);let y=margin;const newPage=()=>{pdf.addPage();y=margin},renderBlock=async block=>{const canvas=await html2canvas(block,{scale:2,backgroundColor:'#ffffff',logging:false,useCORS:true}),imageWidth=contentWidth,imageHeight=canvas.height*imageWidth/canvas.width;if(imageHeight<=usableHeight){if(y+imageHeight>maxY)newPage();pdf.addImage(canvas.toDataURL('image/png'),'PNG',margin,y,imageWidth,imageHeight,undefined,'FAST');y+=imageHeight+4;return}const pixelsPerMm=canvas.width/imageWidth,maxSlicePixels=Math.floor(usableHeight*pixelsPerMm);for(let offset=0;offset<canvas.height;offset+=maxSlicePixels){const sliceHeight=Math.min(maxSlicePixels,canvas.height-offset),slice=document.createElement('canvas');slice.width=canvas.width;slice.height=sliceHeight;slice.getContext('2d').drawImage(canvas,0,offset,canvas.width,sliceHeight,0,0,canvas.width,sliceHeight);if(y>margin)newPage();const sliceMm=sliceHeight/pixelsPerMm;pdf.addImage(slice.toDataURL('image/png'),'PNG',margin,y,imageWidth,sliceMm,undefined,'FAST');y+=sliceMm+4}};for(const block of blocks)await renderBlock(block);const total=pdf.getNumberOfPages();for(let number=1;number<=total;number++){pdf.setPage(number);pdf.setDrawColor(205,214,218);pdf.line(margin,footerY-4,pageWidth-margin,footerY-4);pdf.setFontSize(9);pdf.setTextColor(95,110,120);pdf.text(`${number} / ${total}`,pageWidth-margin,footerY,{align:'right'})}pdf.save(`${fileName.replace(/[\\/:*?"<>|]/g,'-')}.pdf`)}finally{root.remove()}}
$('#reportForm').addEventListener('submit',async event=>{event.preventDefault();const submit=$('#reportScope').value==='student'?$('#printStudentReport'):$('#printReport');submit.disabled=true;const oldLabel=submit.textContent;submit.textContent='PDF 만드는 중…';try{const scope=$('#reportScope').value,includeNames=$('#reportIncludeNames').checked,includeOriginals=$('#reportIncludeOriginals').checked,selectedNumber=Number($('#reportStudent').value);if(scope==='class'&&currentAiAnalysis?.meta?.month!==selectedAnalysisMonth){aiAutoKey='';await ensureAiAnalysis()}if(scope==='class'&&(!currentAiAnalysis||currentAiAnalysis?.meta?.month!==selectedAnalysisMonth))throw new Error('현재 월의 AI 분석 결과를 먼저 불러와 주세요.');const rows=scope==='student'?allResponses.filter(item=>Number(item.student_number)===selectedNumber):allResponses,student=classSettings.students.find(item=>Number(item.number)===selectedNumber),trend=classMonthlyTrend(rows),title=scope==='student'?`${includeNames?student?.name||'학생':'선택 학생'} 보고서`:`${classSettings.grade}학년 ${classSettings.classNumber}반 학급 보고서`,summary=trend.map(row=>`<tr><td>${escapeHTML(monthLabel(row.month))}</td><td>${row.participants}명</td><td>${row.rate}%</td><td>${row.average?.toFixed(1)||'—'}</td></tr>`).join(''),originals=includeOriginals?rows.filter(item=>!item.analysis_excluded).map(item=>{const payload=payloadOf(item),name=includeNames?item.student_name:`학생-${item.student_number}`;return`<article><h3>${escapeHTML(name)} · ${escapeHTML(monthLabel(monthOf(item)))}</h3><p><b>학교생활 고민</b><br>${escapeHTML(payload.studentState?.worryDetail||'작성 내용 없음')}</p><p><b>도움 요청</b> ${escapeHTML(payload.helpNow||'없음')}</p></article>`}).join(''):'';const content=`<header><h1>${escapeHTML(title)}</h1><p>${scope==='student'?'전체 제출':escapeHTML(monthLabel(selectedAnalysisMonth))} 기준 · ${new Date().toLocaleDateString('ko-KR')}</p></header><p class="pdf-warning">이 보고서는 학생 지원을 위한 참고 자료이며 진단이나 사실 판정이 아닙니다.</p>${scope==='student'?buildStudentOverviewReportSection(student)+(currentAiAnalysis?.meta?.month===selectedAnalysisMonth?buildAiReportSectionWithoutTimeline(scope,selectedNumber,includeNames):'')+buildStudentSupportReportSection(student)+buildStudentMonthlyResponseReportSection(student):buildAiReportSection(scope,selectedNumber,includeNames)}<h2>월별 실제 응답 추세</h2><table><thead><tr><th>월</th><th>참여</th><th>참여율</th><th>자기평가 평균</th></tr></thead><tbody>${summary||'<tr><td colspan="4">아직 월별 응답이 없습니다.</td></tr>'}</tbody></table>${includeOriginals?`<h2>선택된 설문 원문</h2>${originals}`:''}`;await downloadPdfDocument(content,`${title}-${selectedAnalysisMonth}`);if($('#reportDialog').open)$('#reportDialog').close();showToast(scope==='student'?'학생 기록 PDF를 다운로드했습니다.':'학급 AI 분석 PDF를 다운로드했습니다.')}catch(error){showToast(`PDF 저장 실패: ${error.message}`)}finally{submit.disabled=false;submit.textContent=oldLabel}});
