function relationshipMonthSnapshot(month){const rows=allResponses.filter(item=>monthOf(item)===month),cumulative=IeumAnalysisCore.cumulativeScores(rows),students=classSettings.students.map(student=>Number(student.number)),mutual=[];students.forEach((a,index)=>students.slice(index+1).forEach(b=>{const ab=cumulative.scores.get(`${a}:${b}`),ba=cumulative.scores.get(`${b}:${a}`);if(ab>=4&&ba>=4)mutual.push(`${a}:${b}`)}));return{month,participants:cumulative.participants.size,relationResponders:cumulative.relationResponders.size,mutual}}
function cumulativeCoverage(){const months=[...new Set(allResponses.map(monthOf).filter(month=>/^\d{4}-\d{2}$/.test(month)))],total=classSettings.students.length,submitted=months.reduce((sum,month)=>sum+latestByStudent(allResponses,month).size,0),relationSubmitted=months.reduce((sum,month)=>sum+[...latestByStudent(allResponses,month).values()].filter(item=>(payloadOf(item).relationships||[]).length).length,0),opportunities=months.length*total;return{months,participation:opportunities?Math.round(submitted/opportunities*100):0,relations:opportunities?Math.round(relationSubmitted/opportunities*100):0}}

var selectedRelationshipMonth='',relationshipMapMode='monthly';
function availableRelationshipMonths(){return[...new Set(allResponses.map(monthOf).filter(month=>/^\d{4}-\d{2}$/.test(month)))].sort()}
function relationshipMapState(){const months=availableRelationshipMonths();if(!months.includes(selectedRelationshipMonth))selectedRelationshipMonth=months.at(-1)||'';const source=relationshipMapMode==='cumulative'?allResponses:allResponses.filter(item=>monthOf(item)===selectedRelationshipMonth),analysis=buildCumulativeRelationshipAnalysis(source),monthIndex=months.indexOf(selectedRelationshipMonth),previousMonth=monthIndex>0?months[monthIndex-1]:'',previous=previousMonth?buildCumulativeRelationshipAnalysis(allResponses.filter(item=>monthOf(item)===previousMonth)):null;return{months,analysis,previousMonth,previous}}

function separateRelationshipPositions(positions,width,height){const entries=[...positions.entries()],minX=132,minY=60,paddingX=68,paddingY=34;for(let pass=0;pass<120;pass++){let moved=false;for(let i=0;i<entries.length;i++)for(let j=i+1;j<entries.length;j++){const [numberA,a]=entries[i],[numberB,b]=entries[j],dx=b.x-a.x,dy=b.y-a.y,overlapX=minX-Math.abs(dx),overlapY=minY-Math.abs(dy);if(overlapX<=0||overlapY<=0)continue;moved=true;if(overlapX/minX<overlapY/minY){const direction=dx===0?(numberA<numberB?1:-1):Math.sign(dx),shift=overlapX/2+.6;a.x-=direction*shift;b.x+=direction*shift}else{const direction=dy===0?(numberA<numberB?1:-1):Math.sign(dy),shift=overlapY/2+.6;a.y-=direction*shift;b.y+=direction*shift}a.x=Math.max(paddingX,Math.min(width-paddingX,a.x));b.x=Math.max(paddingX,Math.min(width-paddingX,b.x));a.y=Math.max(paddingY,Math.min(height-paddingY,a.y));b.y=Math.max(paddingY,Math.min(height-paddingY,b.y))}if(!moved)break}return positions}

